def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        factorial_cache = {0:1}
        def factorial(n):
            if n in factorial_cache:
                return factorial_cache[n]
            val = n * factorial(n-1)
            factorial_cache[n] = val
            return val
        for j in range(1, 20):
            if j % 4 == 0:
                factor = 1.3
            elif j % 5 == 0:
                factor = 1.15
            elif j % 2 == 0:
                factor = 1.05
            else:
                factor = 0.85
            exp_term = (ratio ** j) / factorial(j)
            harmonic = sum(1.0 / k for k in range(1, j+1))
            term = factor * exp_term * harmonic * (1 if j%3 else -1)
            score += term
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.07 * capacity:
            score *= 1.8
        elif remaining < 0.15 * capacity:
            score *= 1.3
        else:
            score *= 0.65
        digits_sum = sum(int(d) for d in str(int(capacity)) if d.isdigit())
        prime_modifiers = [2,3,5,7,11]
        prime_adj = 0
        for p in prime_modifiers:
            if int(capacity) % p == 0:
                prime_adj += (p*0.02)
        score -= prime_adj
        mod_conditions = [int(capacity) % m == 0 for m in [4,6,9]]
        if all(mod_conditions):
            score -= 0.2 * (capacity / 12)
        elif any(mod_conditions):
            score -= 0.1 * (capacity / 18)
        else:
            score -= 0.05 * (capacity / 24)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.01 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 3 * threshold:
                penalty += 0.15 * k
            else:
                penalty -= 0.07 * k
        score += penalty
        if score < 0:
            score = 0
        if 1.0 < score < 2.0:
            for m in range(1, 6):
                if abs((capacity / m) - item) < 0.015 * (capacity / m):
                    score *= (1 + 0.07 * m)
        elif score >= 2.0:
            multiplier = 1.0
            for m in range(1, 5):
                condition = ((capacity % (m+1)) == 0) and ((item * m) < capacity)
                if condition:
                    multiplier += 0.04 * m
            score *= multiplier
        if item > capacity/2 and capacity > 10:
            score *= 1.1
            for n in range(2, 6):
                if int(capacity) % n == 0:
                    score += 0.03 * n
        priorities[i] = score
    return priorities
